"""sklearn.mixture — Gaussian Mixture Models."""
import numpy as np
from sklearn.base import BaseEstimator


class GaussianMixture(BaseEstimator):
    """Gaussian Mixture Model fitted with Expectation-Maximisation.

    Parameters
    ----------
    n_components : int, default=1
    max_iter : int, default=100
    tol : float, default=1e-3
    random_state : int or None, default=None
    covariance_type : str, default='full'
    """

    def __init__(self, n_components=1, *, covariance_type='full', tol=1e-3,
                 reg_covar=1e-6, max_iter=100, n_init=1, init_params='kmeans',
                 weights_init=None, means_init=None, precisions_init=None,
                 random_state=None, warm_start=False, verbose=0,
                 verbose_interval=10):
        self.n_components = n_components
        self.covariance_type = covariance_type
        self.tol = tol
        self.reg_covar = reg_covar
        self.max_iter = max_iter
        self.n_init = n_init
        self.init_params = init_params
        self.weights_init = weights_init
        self.means_init = means_init
        self.precisions_init = precisions_init
        self.random_state = random_state
        self.warm_start = warm_start
        self.verbose = verbose
        self.verbose_interval = verbose_interval

    def fit(self, X, y=None):
        rng = np.random.RandomState(self.random_state)
        X = np.asarray(X, dtype=float)
        n, d = X.shape
        k = self.n_components

        # Init
        idx = rng.choice(n, k, replace=False)
        self.means_ = X[idx].copy()
        self.covariances_ = np.array([np.eye(d)] * k)
        self.weights_ = np.ones(k) / k

        prev_ll = -np.inf
        for _ in range(self.max_iter):
            # E-step
            resp = self._estimate_resp(X)
            # M-step
            Nk = resp.sum(axis=0)
            for c in range(k):
                if Nk[c] < 1e-10:
                    continue
                self.weights_[c] = Nk[c] / n
                self.means_[c] = (resp[:, c:c+1].T @ X).ravel() / Nk[c]
                diff = X - self.means_[c]
                self.covariances_[c] = (diff * resp[:, c:c+1]).T @ diff / Nk[c]
                self.covariances_[c] += 1e-6 * np.eye(d)

            ll = np.sum(np.log(self._weighted_density(X).sum(axis=1) + 1e-300))
            if abs(ll - prev_ll) < self.tol:
                break
            prev_ll = ll

        self.converged_ = True
        return self

    def _log_gauss(self, X, mean, cov):
        d = X.shape[1]
        diff = X - mean
        sign, logdet = np.linalg.slogdet(cov)
        prec = np.linalg.pinv(cov)
        maha = np.sum(diff @ prec * diff, axis=1)
        return -0.5 * (d * np.log(2 * np.pi) + logdet + maha)

    def _weighted_density(self, X):
        k = self.n_components
        densities = np.zeros((X.shape[0], k))
        for c in range(k):
            densities[:, c] = self.weights_[c] * np.exp(self._log_gauss(X, self.means_[c], self.covariances_[c]))
        return densities

    def _estimate_resp(self, X):
        densities = self._weighted_density(X)
        total = densities.sum(axis=1, keepdims=True)
        return densities / (total + 1e-300)

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        return np.argmax(self._estimate_resp(X), axis=1)

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        return self._estimate_resp(X)

    def score(self, X, y=None):
        X = np.asarray(X, dtype=float)
        return np.mean(np.log(self._weighted_density(X).sum(axis=1) + 1e-300))

    def score_samples(self, X):
        X = np.asarray(X, dtype=float)
        return np.log(self._weighted_density(X).sum(axis=1) + 1e-300)


class BayesianGaussianMixture(GaussianMixture):
    """Bayesian Gaussian Mixture (simplified variational inference).

    Uses the same EM as GaussianMixture with a Dirichlet prior on weights
    that encourages sparsity.

    Parameters
    ----------
    n_components : int, default=1
    max_iter : int, default=100
    tol : float, default=1e-3
    random_state : int or None, default=None
    weight_concentration_prior : float, default=0.01
    """

    def __init__(self, n_components=1, *, covariance_type='full', tol=1e-3,
                 reg_covar=1e-6, max_iter=100, n_init=1, init_params='kmeans',
                 weight_concentration_prior_type='dirichlet_process',
                 weight_concentration_prior=0.01, mean_precision_prior=None,
                 mean_prior=None, degrees_of_freedom_prior=None,
                 covariance_prior=None, random_state=None, warm_start=False,
                 verbose=0, verbose_interval=10):
        super().__init__(n_components=n_components, covariance_type=covariance_type,
                         tol=tol, reg_covar=reg_covar, max_iter=max_iter,
                         n_init=n_init, init_params=init_params,
                         random_state=random_state, warm_start=warm_start,
                         verbose=verbose, verbose_interval=verbose_interval)
        self.weight_concentration_prior_type = weight_concentration_prior_type
        self.weight_concentration_prior = weight_concentration_prior
        self.mean_precision_prior = mean_precision_prior
        self.mean_prior = mean_prior
        self.degrees_of_freedom_prior = degrees_of_freedom_prior
        self.covariance_prior = covariance_prior

    def fit(self, X, y=None):
        super().fit(X, y)
        # Apply Dirichlet prior to suppress small components
        alpha = self.weight_concentration_prior
        Nk = self.weights_ * X.shape[0]
        w = Nk + alpha
        self.weights_ = w / w.sum()
        return self
